patch:
--- a/decoder.v
+++ b/decoder.v
@@ -11,7 +11,7 @@ module wrapper(
 );
   decoder_3to8 dec_inst (
     .sel(selector),
-    .output(decoded),
+    .out(decoded),
     .enable(en)
   );
 endmodule

before_code:
module decoder_3to8(
  input [2:0] sel,
  input enable,
  output [7:0] out
);
  assign out = enable ? (1 << sel) : 8'b0;
endmodule

module wrapper(
  input [2:0] selector,
  input en,
  output [7:0] decoded
);
  decoder_3to8 dec_inst (
    .sel(selector),
    .output(decoded),
    .enable(en)
  );
endmodule

after_code:
module decoder_3to8(
  input [2:0] sel,
  input enable,
  output [7:0] out
);
  assign out = enable ? (1 << sel) : 8'b0;
endmodule

module wrapper(
  input [2:0] selector,
  input en,
  output [7:0] decoded
);
  decoder_3to8 dec_inst (
    .sel(selector),
    .out(decoded),
    .enable(en)
  );
endmodule
